cat > server/digifi.js << 'ENDFILE'
const fetch = require('node-fetch');

const DIGIFI_BASE = process.env.DIGIFI_API_BASE_URL || 'https://api.sandbox.digifi.io';
const DIGIFI_KEY = process.env.DIGIFI_API_KEY;
const TOKEN_VAR = process.env.DIGIFI_TRACKING_TOKEN_VAR || 'loan_status_tracking_token';

const VAR_MAP = {
  borrower_first_name: 'borrower_first_name',
  borrower_last_name: 'borrower_last_name',
  property_address: 'borrower_cr_subject_address_tracker',
  pal_delivery_date: 'pal_delivery_date',
  psa_received: 'psa_received_date',
  escrow_opened: 'trust_and_escrow_request_date',
  appraisal_ordered: 'property_appraisal_request_date',
  dd_ordered: 'property_due_diligence_ordered_date',
  appraisal_received: 'property_appraisal_delivered_date',
  dd_cleared: 'property_due_diligence_delivered_date',
  estimated_closing: 'estimated_closing_date',
  lo_name: 'assigned_loan_officer',
  lo_email: 'assigned_loan_officer_email',
  lo_phone: 'assigned_loan_officer_phone',
  tracking_token: TOKEN_VAR,
};

var STATUS_ORDER = [
  'Application Started', 'Incomes and Employment', 'Financial Assets',
  'Prequal Request', 'Residency', 'Application Submission', 'Pre-Approved!',
  'Conditions Review', 'In Processing', 'In Underwriting',
  'Additional Tasks Required', 'Clear to Close', 'Closing',
  'Closing Docs Issued', 'Closing Docs Received', 'Funded'
];

function statusAtOrPast(currentStatus, targetStatus) {
  var ci = STATUS_ORDER.indexOf(currentStatus);
  var ti = STATUS_ORDER.indexOf(targetStatus);
  if (ci === -1 || ti === -1) return false;
  return ci >= ti;
}

const MOCK_DATA = {
  borrower_first_name: 'John',
  borrower_last_name: 'Garcia',
  property_address: '123 Playa Hermosa, Guanacaste, Costa Rica',
  estimated_closing: 'March 15, 2026',
  lo_name: 'Raj Ponniah',
  lo_email: 'raj@mysecondstreet.com',
  lo_phone: '+1 (949) 339-1660',
  milestones: [
    { label: 'Application received', date: null, noDate: true, status: 'done', section: 'Application' },
    { label: 'Submitted to underwriting', date: null, noDate: true, status: 'done', section: 'Application' },
    { label: 'Pre-approval issued', date: 'Jan 15, 2026', noDate: false, status: 'done', section: 'Application' },
    { label: 'PSA received', date: 'Jan 20, 2026', noDate: false, status: 'done', section: 'PSA & services ordered' },
    { label: 'Escrow opened', date: 'Jan 22, 2026', noDate: false, status: 'done', section: 'PSA & services ordered' },
    { label: 'Appraisal ordered', date: 'Jan 25, 2026', noDate: false, status: 'done', section: 'PSA & services ordered' },
    { label: 'Due diligence ordered', date: null, noDate: false, status: 'active', section: 'PSA & services ordered' },
    { label: 'Appraisal received', date: null, noDate: false, status: 'pending', section: 'Results & clearances' },
    { label: 'Due diligence cleared', date: null, noDate: false, status: 'pending', section: 'Results & clearances' },
    { label: 'Clear to close', date: null, noDate: true, status: 'pending', section: 'Closing' },
    { label: 'Closing documents issued', date: null, noDate: true, status: 'pending', section: 'Closing' },
    { label: 'Closing complete', date: null, noDate: true, status: 'pending', section: 'Closing' },
  ],
};

function hasDate(val) {
  return val && typeof val === 'string' && val.trim() !== '';
}

function buildMilestones(vars, appStatus) {
  var raw = [
    { label: 'Application received', dateKey: null, noDate: true, section: 'Application', statusTrigger: null },
    { label: 'Submitted to underwriting', dateKey: null, noDate: true, section: 'Application', statusTrigger: null },
    { label: 'Pre-approval issued', dateKey: 'pal_delivery_date', noDate: false, section: 'Application', statusTrigger: null },
    { label: 'PSA received', dateKey: 'psa_received', noDate: false, section: 'PSA & services ordered', statusTrigger: null },
    { label: 'Escrow opened', dateKey: 'escrow_opened', noDate: false, section: 'PSA & services ordered', statusTrigger: null },
    { label: 'Appraisal ordered', dateKey: 'appraisal_ordered', noDate: false, section: 'PSA & services ordered', statusTrigger: null },
    { label: 'Due diligence ordered', dateKey: 'dd_ordered', noDate: false, section: 'PSA & services ordered', statusTrigger: null },
    { label: 'Appraisal received', dateKey: 'appraisal_received', noDate: false, section: 'Results & clearances', statusTrigger: null },
    { label: 'Due diligence cleared', dateKey: 'dd_cleared', noDate: false, section: 'Results & clearances', statusTrigger: null },
    { label: 'Clear to close', dateKey: null, noDate: true, section: 'Closing', statusTrigger: 'Clear to Close' },
    { label: 'Closing documents issued', dateKey: null, noDate: true, section: 'Closing', statusTrigger: 'Closing Docs Issued' },
    { label: 'Closing complete', dateKey: null, noDate: true, section: 'Closing', statusTrigger: 'Funded' },
  ];

  var anyDateStepHasDate = raw.slice(2).some(function(m) {
    if (m.noDate || !m.dateKey) return false;
    return hasDate(vars[VAR_MAP[m.dateKey]]);
  });

  var firstPending = -1;
  return raw.map(function(m, i) {
    var date = null;
    var status;
    if (m.dateKey && VAR_MAP[m.dateKey]) date = vars[VAR_MAP[m.dateKey]] || null;

    if (i === 0) {
      status = 'done';
    } else if (i === 1) {
      status = anyDateStepHasDate ? 'done' : (firstPending === -1 ? 'active' : 'pending');
      if (status !== 'done' && firstPending === -1) firstPending = i;
    } else if (m.statusTrigger) {
      if (statusAtOrPast(appStatus, m.statusTrigger)) {
        status = 'done';
      } else {
        status = firstPending === -1 ? 'active' : 'pending';
        if (firstPending === -1) firstPending = i;
      }
    } else {
      if (hasDate(date)) {
        status = 'done';
      } else {
        status = firstPending === -1 ? 'active' : 'pending';
        if (firstPending === -1) firstPending = i;
      }
    }

    return { label: m.label, date: hasDate(date) ? date : null, noDate: m.noDate, status: status, section: m.section };
  });
}

async function getApplicationByToken(token) {
  if (token === 'demo' || token === 'test') {
    console.log('[DEV] Demo token — returning mock data');
    return { success: true, data: MOCK_DATA };
  }
  if (!DIGIFI_KEY || DIGIFI_KEY === 'your_digifi_api_key_here') {
    return { success: false, error: 'not_found' };
  }
  try {
    var searchUrl = DIGIFI_BASE + '/applications/search?searchByFields=' + encodeURIComponent(TOKEN_VAR) + '&searchValue=' + encodeURIComponent(token) + '&limit=1';
    var response = await fetch(searchUrl, {
      headers: { 'x-api-key': DIGIFI_KEY, 'Content-Type': 'application/json' },
    });
    if (!response.ok) {
      console.error('Digifi API error: ' + response.status + ' ' + response.statusText);
      var errBody = await response.text();
      console.error('Response body: ' + errBody);
      return { success: false, error: 'api_error' };
    }
    var result = await response.json();
    var applications = result.items || result.data || result.applications || result;
    if (!applications || (Array.isArray(applications) && applications.length === 0)) return { success: false, error: 'not_found' };
    var app = Array.isArray(applications) ? applications[0] : applications;
    var vars = app.variables || {};
    var appStatus = app.statusName || app.status || '';
    var milestones = buildMilestones(vars, appStatus);
    var completedCount = milestones.filter(function(m) { return m.status === 'done'; }).length;
    return {
      success: true,
      data: {
        borrower_first_name: vars[VAR_MAP.borrower_first_name] || '',
        borrower_last_name: vars[VAR_MAP.borrower_last_name] || '',
        property_address: vars[VAR_MAP.property_address] || '',
        estimated_closing: vars[VAR_MAP.estimated_closing] || null,
        lo_name: vars[VAR_MAP.lo_name] || '',
        lo_email: vars[VAR_MAP.lo_email] || '',
        lo_phone: vars[VAR_MAP.lo_phone] || '',
        milestones: milestones,
        completed_count: completedCount,
        total_steps: 12,
      },
    };
  } catch (err) {
    console.error('Digifi API fetch error:', err.message);
    return { success: false, error: 'api_error' };
  }
}

module.exports = { getApplicationByToken, MOCK_DATA };
ENDFILE

cat > server/index.js << 'ENDFILE'
require('dotenv').config({ path: require('path').join(__dirname, '..', '.env') });
var express = require('express');
var cors = require('cors');
var path = require('path');
var digifi = require('./digifi');

var app = express();
var PORT = process.env.PORT || 3001;
var CLIENT_URL = process.env.CLIENT_URL || 'http://localhost:5173';

app.use(cors({ origin: CLIENT_URL }));
app.use(express.json());

var rateLimitMap = new Map();
function rateLimit(req, res, next) {
  var ip = req.ip || req.connection.remoteAddress;
  var now = Date.now();
  var entry = rateLimitMap.get(ip);
  if (!entry || now - entry.start > 60000) { rateLimitMap.set(ip, { start: now, count: 1 }); return next(); }
  entry.count++;
  if (entry.count > 30) return res.status(429).json({ error: 'Too many requests.' });
  next();
}

app.get('/api/track/:token', rateLimit, async function(req, res) {
  var token = req.params.token;
  if (!token || token.length < 4 || token.length > 64 || !/^[a-zA-Z0-9\-_]+$/.test(token)) {
    return res.status(400).json({ error: 'Invalid tracking code.' });
  }
  try {
    var result = await digifi.getApplicationByToken(token);
    if (!result.success) {
      if (result.error === 'not_found') return res.status(404).json({ error: 'No loan found for this tracking code.' });
      return res.status(502).json({ error: 'Unable to retrieve loan status.' });
    }
    return res.json(result.data);
  } catch (err) {
    console.error('Track error:', err);
    return res.status(500).json({ error: 'An unexpected error occurred.' });
  }
});

app.get('/api/health', function(req, res) { res.json({ status: 'ok' }); });

if (process.env.NODE_ENV === 'production') {
  var clientBuild = path.join(__dirname, '..', 'client', 'dist');
  app.use(express.static(clientBuild));
  app.get('*', function(req, res) {
    if (!req.path.startsWith('/api')) res.sendFile(path.join(clientBuild, 'index.html'));
  });
}

app.listen(PORT, function() {
  console.log('Second Street Status Tracker running on port ' + PORT);
  if (!process.env.DIGIFI_API_KEY || process.env.DIGIFI_API_KEY === 'your_digifi_api_key_here') {
    console.log('No Digifi API key — using mock data. Test: /api/track/demo');
  }
});
ENDFILE

