import React, { useEffect, useState } from 'react';
export default function ProgressRing({ completed, total }) {
  const [offset, setOffset] = useState(194.8);
  const pct = Math.round((completed / total) * 100);
  const circumference = 194.8;
  useEffect(() => { const t = setTimeout(() => setOffset(circumference - (circumference * pct / 100)), 300); return () => clearTimeout(t); }, [pct]);
  return (
    <div className="relative w-[80px] h-[80px] flex-shrink-0">
      <svg viewBox="0 0 76 76" className="-rotate-90">
        <circle cx="38" cy="38" r="31" fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth="5" />
        <circle cx="38" cy="38" r="31" fill="none" stroke="#fff" strokeWidth="5" strokeLinecap="round"
          strokeDasharray={circumference} strokeDashoffset={offset} style={{transition:'stroke-dashoffset 1.2s ease'}} />
      </svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center">
        <span className="text-[20px] font-bold text-white leading-none">{pct}%</span>
        <span className="text-[8px] text-white/55 uppercase tracking-wider mt-0.5">Complete</span>
      </div>
    </div>
  );
}
