import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import ProgressRing from '../components/ProgressRing';
import MilestoneSection from '../components/MilestoneSection';
import LoanOfficerCard from '../components/LoanOfficerCard';
export default function TrackerPage() {
  const { token } = useParams();
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    (async () => {
      try {
        const res = await fetch('/api/track/'+token);
        if (!res.ok) { const e = await res.json(); setError(e.error||'Unable to load.'); return; }
        setData(await res.json());
      } catch(e) { setError('Unable to connect.'); }
      finally { setLoading(false); }
    })();
  }, [token]);
  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-[#F5F6FA]">
      <div className="text-center">
        <div className="w-10 h-10 border-[3px] border-ss-blue/20 border-t-ss-blue rounded-full animate-spin mx-auto mb-4"/>
        <p className="text-sm text-gray-400 font-medium">Loading loan status...</p>
      </div>
    </div>
  );
  if (error) return (
    <div className="min-h-screen flex items-center justify-center bg-[#F5F6FA] px-6">
      <div className="text-center max-w-md">
        <img src="/assets/logo-white.jpg" alt="Second Street" className="h-8 mx-auto mb-6 invert" />
        <h1 className="font-serif text-2xl text-navy mb-2">Link not found</h1>
        <p className="text-sm text-gray-500 leading-relaxed mb-6">{error}</p>
        <p className="text-xs text-gray-400">Need help? <a href="mailto:hello@mysecondstreet.com" className="text-ss-blue">hello@mysecondstreet.com</a> &bull; <a href="tel:+19493391660" className="text-ss-blue">+1 (949) 339-1660</a></p>
      </div>
    </div>
  );
  const done = data.milestones.filter(m=>m.status==='done').length;
  const active = data.milestones.find(m=>m.status==='active');
  const total = data.milestones.length;
  const sections = [];
  var currentSection = null;
  data.milestones.forEach(function(m) {
    if (m.section !== currentSection) {
      currentSection = m.section;
      sections.push({ title: currentSection, milestones: [] });
    }
    sections[sections.length - 1].milestones.push(m);
  });
  return (
    <div className="min-h-screen bg-[#F5F6FA]">
      <div className="bg-gradient-to-br from-navy via-[#1a2468] to-ss-blue relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 rounded-full bg-white/[0.04]"/>
        <div className="absolute -bottom-6 right-20 w-24 h-24 rounded-full bg-white/[0.03]"/>
        <div className="max-w-3xl mx-auto px-6 py-8 relative z-10">
          <div className="flex items-center gap-3 mb-6">
            <img src="/assets/logo-white.jpg" alt="Second Street" className="h-7" />
            <span className="text-white/40 text-xs font-medium uppercase tracking-widest ml-1">Loan Status</span>
          </div>
          <div className="flex items-center gap-5 flex-wrap">
            <ProgressRing completed={done} total={total}/>
            <div>
              <h1 className="font-serif text-xl text-white mb-1">{data.borrower_first_name} {data.borrower_last_name}</h1>
              <p className="text-[12px] text-white/65 leading-relaxed">{data.property_address}</p>
              {data.estimated_closing&&<div className="mt-1.5 text-[11px] font-semibold text-white/85">Est. closing: <span className="bg-white/15 px-2.5 py-0.5 rounded-full ml-1">{data.estimated_closing}</span></div>}
            </div>
          </div>
        </div>
      </div>
      <div className="max-w-3xl mx-auto px-6 -mt-5 relative z-20 pb-10">
        <div className="flex gap-2.5 mb-5 flex-wrap">
          <div className="flex-1 min-w-[130px] bg-white rounded-xl p-3.5 shadow-sm border border-ss-border">
            <div className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-1">Milestones</div>
            <div className="text-lg font-bold text-navy">{done} / {total}</div>
          </div>
          <div className="flex-1 min-w-[130px] bg-white rounded-xl p-3.5 shadow-sm border border-ss-border">
            <div className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider mb-1">Current step</div>
            <div className={`text-[13px] font-bold leading-snug ${active?'text-ss-blue':'text-ss-green'}`}>{active?active.label:'Complete!'}</div>
          </div>
        </div>
        {sections.map(s=><MilestoneSection key={s.title} title={s.title} milestones={s.milestones}/>)}
        <LoanOfficerCard name={data.lo_name} email={data.lo_email} phone={data.lo_phone}/>
        <div className="mt-6 text-center text-[11px] text-gray-400 leading-relaxed">
          <p className="font-medium text-gray-500 mb-1">Second Street Inc. &bull; Second Street CR, S.R.L.</p>
          <p>This page updates automatically as your loan progresses.</p>
          <p className="mt-1">Questions? <a href="mailto:hello@mysecondstreet.com" className="text-ss-blue">hello@mysecondstreet.com</a> &bull; <a href="tel:+19493391660" className="text-ss-blue">+1 (949) 339-1660</a></p>
        </div>
      </div>
    </div>
  );
}
ENDFILE

